={{ (() => {
  // 1) localizar el texto con el JSON (según tu screenshot)
  const raw =
    $json?.content?.parts?.[0]?.text ??
    $json?.content?.[0]?.text ??
    $json?.candidates?.[0]?.content?.parts?.[0]?.text ??
    '';

  // 2) limpiar fences ```json ... ``` y espacios
  let s = String(raw).trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```/i, '')
    .replace(/```$/i, '')
    .trim();

  // 3) intentar parseo directo; si falla, desescapar y reintentar
  const tryParse = (t) => {
    try {
      const obj = JSON.parse(t);
      return Array.isArray(obj) ? obj : [obj];
    } catch (_) {
      return null;
    }
  };

  let arr = tryParse(s);
  if (!arr) {
    const unesc = s
      .replace(/\\n/g, ' ')
      .replace(/\\t/g, ' ')
      .replace(/\\"/g, '"')
      .replace(/^"|"$/g, '');
    arr = tryParse(unesc);
  }

  return arr || []; // devolver SIEMPRE un array
})() }}

={{ (() => {
  // 1) Leer salida del nodo de IA
  const v = $json?.content ?? $json?.choices?.[0]?.message?.content ?? '';

  // 2) Normalizar a string
  let s = Array.isArray(v) ? String(v[0] ?? '') : String(v);

  // 3) Quitar fences y espacios
  s = s
    .replace(/^```json\s*/i, '')
    .replace(/^```/i, '')
    .replace(/```$/i, '')
    .trim();

  // 4) Si todo viene entrecomillado, quitar comillas exteriores y desescapar
  if (s.startsWith('"') && s.endsWith('"')) {
    s = s.slice(1, -1);
  }
  s = s.replace(/\\n/g, ' ')
       .replace(/\\t/g, ' ')
       .replace(/\\"/g, '"');

  const toArray = (txt) => {
    // a) intento directo
    try {
      const first = JSON.parse(txt);
      return Array.isArray(first) ? first : [first];
    } catch {}

    // b) si era JSON dentro de string, parseo doble
    try {
      const inner = JSON.parse(txt);
      if (typeof inner === 'string') {
        const second = JSON.parse(inner);
        return Array.isArray(second) ? second : [second];
      }
    } catch {}

    // c) recorte entre llaves por si hay ruido
    const i = txt.indexOf('{'), j = txt.lastIndexOf('}');
    if (i >= 0 && j > i) {
      try { return [ JSON.parse(txt.slice(i, j + 1)) ]; } catch {}
    }
    return [];
  };

  return toArray(s);
})() }}

